INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Servers and channels$q$, $q$Organize communities into servers with multiple text and voice channels, similar to Discord's structure.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Voice chat$q$, $q$Real-time voice communication within community servers, refreshed as part of the 2025 Stoat rebrand.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Self-hosting support$q$, $q$Anyone can deploy their own instance of Stoat using the open-source, Rust-based codebase.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Cross-platform clients$q$, $q$Native apps for Windows, macOS, Linux, and Android, plus a web client, with iOS in development.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Privacy-first design$q$, $q$Built in Europe under EU data protection principles with a short, readable privacy policy and no ad-driven data mining.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Open-source codebase$q$, $q$Publicly available source code under the AGPLv3 license, enabling community audits and contributions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Markdown and file sharing$q$, $q$Rich text formatting and file or media attachments within conversations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Donation-based funding model$q$, $q$No subscription tiers gate core functionality; development is supported by voluntary user donations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Completely free with no paywalled core features$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Open-source and self-hostable for full data control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Privacy-focused, EU-based data handling$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Actively growing user base and rapid feature development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Familiar Discord-like interface lowers the learning curve$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Smaller ecosystem of bots, integrations, and third-party apps compared to Discord$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$iOS app was still in development as of the 2025-2026 rebrand$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Rapid user growth has occasionally strained platform infrastructure$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Recent rebrand from Revolt to Stoat may cause naming confusion$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Fewer enterprise-oriented support or compliance options than commercial community platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Is Stoat the same product as Revolt?$q$, $q$Yes. Stoat is the rebranded name for the chat platform previously known as Revolt. The team renamed it in October 2025 after receiving a cease-and-desist letter regarding the Revolt trademark.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Is Stoat free to use?$q$, $q$Yes, Stoat is entirely free. There is no paid subscription tier for core features, and development is funded through user donations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Can I self-host Stoat?$q$, $q$Yes. Stoat is open source under the AGPLv3 license and can be self-hosted on your own infrastructure for full control over your data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$What platforms does Stoat support?$q$, $q$Stoat has native clients for Windows, macOS, Linux, and Android, plus a web client. An iOS app is in active development.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Who makes Stoat?$q$, $q$Stoat is developed by Revolt Platforms Ltd, a company registered in London, United Kingdom, together with an open-source community of contributors.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$How is Stoat different from Discord?$q$, $q$Stoat offers similar servers, channels, and voice chat functionality, but is open source, self-hostable, ad-free, and built around EU-style data privacy principles rather than a data-driven advertising model.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Does Stoat support voice chat?$q$, $q$Yes, Stoat includes a voice chat system that was refreshed as part of the October 2025 rebrand.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Privacy-conscious online communities$q$, $q$Groups that want Discord-style servers and channels without ad tracking or data mining can run their community on Stoat.$q$, $q$Community managers and moderators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Self-hosted team or hobbyist chat$q$, $q$Technical teams can deploy their own Stoat instance to keep all chat data on infrastructure they control.$q$, $q$Developers and IT-savvy organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Discord alternative during regional restrictions$q$, $q$Users in regions where Discord faces access restrictions have adopted Stoat as a functioning alternative for voice and text communication.$q$, $q$International gaming and social communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$Community (Free / Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited servers and channels","Voice and text chat","File sharing and markdown support","Self-hosting option with full source code access","No ads or paid tiers"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$overview$q$, $q$What Is Stoat$q$, 2, ARRAY[$q$Stoat is a free, open-source chat and community platform designed for people who want the group-chat experience of Discord or Slack without a surveillance-based business model behind it. The project began life as Revolt in early 2021 and was rebranded to Stoat in October 2025 after the development team received a cease-and-desist letter over the Revolt trademark.$q$, $q$The platform is built and maintained by Revolt Platforms Ltd, a UK-registered company, alongside an active open-source community on GitHub. Because the code is public and licensed under AGPLv3, anyone can inspect it, self-host their own instance, or contribute new features rather than relying solely on the hosted stoat.chat service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Stoat offers servers and channels for organizing communities, real-time text chat, voice chat, direct messaging, file and media sharing, and markdown formatting. It is built in Europe and designed around EU data protection principles, with a privacy policy short enough for users to actually read.$q$, $q$Because the backend is written in Rust and the project supports self-hosting, technical teams and privacy-focused communities can run their own independent Stoat servers instead of depending on the company's hosted infrastructure. Native and web clients are available across desktop and mobile, with iOS support in active development.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Stoat has no paid subscription plan for its core chat features. The entire platform is free to use, and ongoing development is funded through user donations rather than advertising or data monetization. Communities and organizations that prefer not to manage their own servers can use the hosted stoat.chat service at no cost, while technically inclined users can self-host the open-source codebase for complete control over their data.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4ec9cb7b-3758-48d4-b21c-ca4d6d43754e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Interactive guides and decision trees$q$, $q$Branching, clickable walkthroughs that adapt to user choices instead of static help articles.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$AI-assisted routing$q$, $q$Automatically directs customers to the most relevant guide or answer based on their query.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Knowledge base builder$q$, $q$Create and host a searchable, brandable knowledge base alongside interactive content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Help desk integrations$q$, $q$Connects with Zendesk, Freshdesk, Front, and other support tools to surface guides during live conversations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Analytics and deflection reporting$q$, $q$Tracks guide views, completion rates, and support ticket deflection to measure self-service impact.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Multilingual and white-label support$q$, $q$Publish guides in multiple languages with custom branding on higher-tier plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Embeddable widgets and in-app tooltips$q$, $q$Deploy guides on websites, inside products, or as standalone help center pages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$User targeting and triggers$q$, $q$Show specific guides to specific user segments based on behavior or account attributes.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Reduces support ticket volume through effective self-service guides$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Flexible deployment as embedded widgets, tooltips, or a full knowledge base$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Strong help desk integrations with Zendesk, Freshdesk, and Front$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Detailed analytics on guide performance and deflection$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Free tier available for small-scale testing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Higher-tier plans can be expensive for smaller teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Guide view limits on lower plans can be restrictive for high-traffic sites$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Multilingual and white-label features are gated behind paid tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Building complex decision trees requires upfront content design effort$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Enterprise features like SSO require custom sales conversations$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$What is Stonly used for?$q$, $q$Stonly is used to build interactive guides, decision trees, and self-service help content that reduce customer support ticket volume and improve product onboarding.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Does Stonly have a free plan?$q$, $q$Yes, Stonly offers a free Basic tier with 400 guide views per month, 5 published guides, and 1 team member.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$How much does Stonly cost?$q$, $q$Paid plans start around 99 to 124 US dollars per month for the Starter tier, depending on billing cycle, with the Business tier priced around 199 to 249 US dollars per month. Enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Does Stonly integrate with help desks?$q$, $q$Yes, Stonly integrates with Zendesk, Freshdesk, Front, and other support platforms so agents can use guides directly inside live conversations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Can Stonly guides be multilingual?$q$, $q$Yes, multilingual guide support is available starting on the Starter and Business plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Who founded Stonly and where is it based?$q$, $q$Stonly was founded in 2018 and is headquartered in Levallois-Perret, France, near Paris.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Does Stonly use AI?$q$, $q$Yes, Stonly includes AI-assisted features that help route customers to the correct guide or generate draft answers from existing content.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Support ticket deflection$q$, $q$Customer support teams embed interactive guides on help center pages so customers can resolve common issues without contacting an agent.$q$, $q$Customer support and helpdesk teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Product onboarding walkthroughs$q$, $q$Product teams use Stonly guides as in-app tooltips to walk new users through setup and key features.$q$, $q$Product and customer success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Agent-assisted troubleshooting$q$, $q$Support agents follow Stonly decision trees during live chat or phone conversations to standardize troubleshooting steps.$q$, $q$Support agents and team leads$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Basic$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["400 guide views per month","5 published guides","1 team member","Single language, up to 100 steps per guide"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Starter$q$, $q$$99-$124/month$q$, $q$monthly or annual$q$, NULL, $q$["Up to 30 interactive guides","Custom knowledge base","Analytics","Custom branding","Zendesk, Freshdesk, and Front integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Business$q$, $q$$199-$249/month$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited guides","Multiple knowledge bases","User targeting","CSS customization","Multilingual support","Segment integration","SEO optimization"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Custom integrations","SSO","Private knowledge bases","White-label options","Dedicated customer success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$overview$q$, $q$What Is Stonly$q$, 2, ARRAY[$q$Stonly is an interactive guide platform used by support, product, and customer success teams to build step-by-step walkthroughs, decision trees, and AI-driven help content. Instead of static help center articles, Stonly guides adapt based on the choices a user makes, walking them toward a resolution or the right next action.$q$, $q$Founded in 2018 and based in Levallois-Perret, France, Stonly serves companies that want to reduce inbound support ticket volume by letting customers solve problems themselves, while still giving support agents the same interactive guides to use during live conversations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Stonly's core building block is the interactive guide: a branching, clickable flow that can include text, images, video, and embedded forms. Guides can be triggered automatically based on user behavior, page context, or support tool integrations, and can be published to a help center, embedded widget, or in-product tooltip.$q$, $q$The platform includes analytics on guide performance and deflection rates, multilingual content support, custom branding and CSS controls, and integrations with help desks such as Zendesk, Freshdesk, and Front, as well as data tools like Segment. Newer AI capabilities help route users to the right guide automatically and can generate draft answers from existing knowledge base content.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28d621bc-8148-478e-91f4-93954281f173', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Stonly offers a free Basic tier with 400 guide views per month, 5 published guides, and 1 team member, suitable for testing the product on a small scale. The Starter plan is priced around 99 US dollars per month billed annually, or 124 US dollars per month billed monthly, and adds up to 30 guides, a custom knowledge base, analytics, and help desk integrations.$q$, $q$The Business plan is priced around 199 US dollars per month billed annually, or 249 US dollars per month billed monthly, and unlocks unlimited guides, multiple knowledge bases, multilingual support, and SEO optimization. Enterprise pricing is custom and adds single sign-on, private knowledge bases, white-label options, and a dedicated customer success manager.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Visual OpenAPI designer$q$, $q$Design API specifications visually without hand-writing raw OpenAPI YAML or JSON.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Interactive documentation$q$, $q$Automatically generated, browsable API documentation kept in sync with the design.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Instant mock servers$q$, $q$Spin up mock APIs from a specification so frontend and backend teams can work in parallel.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Reusable style guides and components$q$, $q$Shared models and style rules enforce consistency across many APIs and teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Multi-branch and version support$q$, $q$Manage API design changes across branches before merging into a stable specification.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Enterprise governance controls$q$, $q$SSO via LDAP or SAML, activity logs, and custom domains on higher-tier plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$SmartBear platform integration$q$, $q$Stoplight's design and mocking tools are integrated into SmartBear's broader API development suite.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$API portfolio visibility$q$, $q$Centralized view of an organization's full API catalog for program and platform leaders.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Strong design-first workflow with visual OpenAPI editing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Mock servers accelerate parallel frontend and backend development$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Reusable style guides help enforce API governance at scale$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Backed by SmartBear's broader API tooling and resources post-acquisition$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Free tier available for individual users testing the product$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Pricing scales quickly with user count on team plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Some standalone Stoplight capabilities are being folded into SmartBear's unified platform, which can mean workflow changes for existing users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Advanced governance features like SSO require higher-tier plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Smaller company footprint (11-50 employees) compared to larger API tooling competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Enterprise pricing requires a custom sales conversation$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$What is Stoplight used for?$q$, $q$Stoplight is used to design, document, and mock APIs using a design-first workflow, letting teams agree on an API contract before writing implementation code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Is Stoplight still an independent company?$q$, $q$No. Stoplight was acquired by SmartBear in 2023, and its design, mocking, and governance capabilities are being integrated into SmartBear's broader API development platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Does Stoplight have a free plan?$q$, $q$Yes, Stoplight offers a free plan for 1 user and 1 project with core design and documentation features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$How much does Stoplight cost?$q$, $q$Paid plans range from roughly 44 US dollars per month for the Basic tier to roughly 362 US dollars per month for the Pro Team tier, depending on billing cycle and user count, with custom Enterprise pricing above that.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Who founded Stoplight?$q$, $q$Stoplight was founded in 2015 by Marc MacLeod in Austin, Texas.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Does Stoplight support mock servers?$q$, $q$Yes, Stoplight can generate instant mock servers directly from an OpenAPI specification.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$What companies use Stoplight?$q$, $q$Publicly referenced Stoplight customers include Calendly, Schneider Electric, Fiserv, and PagerDuty.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Design-first API development$q$, $q$Engineering teams define an OpenAPI contract in Stoplight before writing backend code, keeping frontend and backend work in sync.$q$, $q$API and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$API governance at scale$q$, $q$Large organizations use shared style guides and components to enforce consistent standards across dozens or hundreds of APIs.$q$, $q$API program leaders and architects$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Interactive API documentation$q$, $q$Teams publish auto-generated, always up-to-date documentation for internal or external API consumers.$q$, $q$Developer experience and technical writing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 user","1 project","Core API design and documentation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Basic$q$, $q$$44-$56/month$q$, $q$monthly or annual$q$, NULL, $q$["3 users included","OpenAPI visual designer","Interactive docs","Instant mock servers","Additional users at roughly $11/month each (annual)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Startup$q$, $q$$113-$147/month$q$, $q$monthly or annual$q$, NULL, $q$["8 users included","Private projects","Multi-branch support","Custom domains","Google Analytics integration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Pro Team$q$, $q$$362-$453/month$q$, $q$monthly or annual$q$, NULL, $q$["15 users included","Up to 20 teams","Shared style guides","LDAP/SAML SSO","Activity logs","Component libraries","Additional users at roughly $22/month each (annual)"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Unlimited projects and teams","Custom invoicing and payment terms","Priority support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$overview$q$, $q$What Is Stoplight$q$, 2, ARRAY[$q$Stoplight is a platform for designing, documenting, and mocking APIs using a design-first methodology. Rather than writing code first and documenting it afterward, teams use Stoplight to define an API's contract with OpenAPI specifications first, then build implementation against that agreed-upon design.$q$, $q$Founded in 2015 in Austin, Texas by Marc MacLeod, Stoplight grew into a platform used by API platform teams, developer experience teams, and enterprises standardizing API governance. In August 2023, SmartBear announced its acquisition of Stoplight, combining Stoplight's design-first tooling with SmartBear's existing API testing, documentation, and portal products.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Stoplight includes a visual OpenAPI editor, interactive API documentation, and instant mock servers that let frontend and backend teams work in parallel from an agreed API contract. Reusable style guides, shared components, and models help large organizations enforce consistency across many APIs.$q$, $q$For larger teams, Stoplight adds multi-branch support, custom domains, activity logs, and single sign-on through LDAP or SAML, along with shared style guides and component libraries that scale governance across up to 20 teams on higher plans.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28f84c5e-8df6-4846-8228-5943ba6223e8', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Stoplight offers a free plan limited to 1 user and 1 project with core design and documentation features. The Basic plan is priced around 44 US dollars per month billed annually or 56 US dollars per month billed monthly, and includes 3 users with additional users available at roughly 11 US dollars per month each on annual billing.$q$, $q$The Startup plan is priced around 113 US dollars per month annually or 147 US dollars monthly for 8 users, and adds private projects, multi-branch support, and custom domains. The Pro Team plan is priced around 362 US dollars per month annually or 453 US dollars monthly for 15 users, adding SSO, shared style guides, and component libraries. Enterprise pricing is custom, with unlimited projects and teams. All paid plans include a 14-day free trial.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Git-based automatic deployments$q$, $q$Every push to a configured branch triggers an automatic build and deployment with zero required configuration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Zero-downtime rolling deployments$q$, $q$Releases roll out without interrupting live traffic on production applications.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Custom domains with automatic TLS$q$, $q$Connect custom domains and automatically provision TLS certificates.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Multi-framework and multi-language support$q$, $q$Supports Node.js, Astro, Nuxt, Next.js, Svelte, FastAPI, Go, and Rust applications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Self-hosting option$q$, $q$Deploy Stormkit on your own infrastructure for full control and no vendor lock-in.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Analytics and error monitoring$q$, $q$Real-time performance tracking and error monitoring built into the platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Secure environment variables$q$, $q$Manage configuration secrets for both client-side and server-side applications.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Audit logs and approval mode$q$, $q$Team governance controls available on the Premium and Ultimate plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Self-hosting option avoids vendor lock-in common with managed platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Free plan offers unlimited usage without requiring a credit card$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Broad framework and language support beyond just JavaScript frontends$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Reports significantly lower infrastructure costs versus managed alternatives$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Zero-downtime deployments and automatic TLS reduce operational overhead$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Smaller ecosystem and community compared to Vercel or Netlify$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Founding year, headquarters, and team size are not publicly disclosed$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Self-hosting requires more setup and maintenance effort than a fully managed platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Per-seat pricing on paid tiers can add up for larger teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Enterprise support engagement pricing is not fully transparent$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$What is Stormkit used for?$q$, $q$Stormkit is used to deploy, host, and manage web applications with Git-based CI/CD, either on Stormkit's hosted service or self-hosted on a team's own infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Is Stormkit free to use?$q$, $q$Yes, Stormkit offers a free plan with unlimited usage and community support, with no credit card required to get started.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$How is Stormkit different from Vercel or Netlify?$q$, $q$Stormkit offers a self-hosted deployment option so teams can run the platform on their own infrastructure, aiming to avoid vendor lock-in and reduce hosting costs compared to fully managed platforms.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$What frameworks does Stormkit support?$q$, $q$Stormkit supports JavaScript frontend and backend frameworks such as Next.js, Nuxt, Astro, and Svelte, as well as Go, Rust, and FastAPI applications.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$How much does Stormkit cost?$q$, $q$Stormkit has a free tier, a Premium plan at 20 US dollars per month per seat, and an Ultimate plan at 100 US dollars per month per seat, plus a custom enterprise services engagement.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Does Stormkit support custom domains?$q$, $q$Yes, Stormkit supports custom domains with automatic TLS certificate provisioning.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Can Stormkit be self-hosted?$q$, $q$Yes, Stormkit can be self-hosted on a team's own infrastructure for full control over deployments and data.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Self-hosted CI/CD for web apps$q$, $q$Engineering teams deploy Stormkit on their own infrastructure to get Git-based CI/CD without depending on a third-party cloud vendor.$q$, $q$Platform and DevOps engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Cost-conscious hosting for growing products$q$, $q$Startups and agencies use Stormkit to reduce hosting costs versus fully managed platforms while keeping a similar deployment experience.$q$, $q$Startups and digital agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Multi-framework application hosting$q$, $q$Teams running a mix of JavaScript, Go, and Rust services use Stormkit to deploy all of them from a single platform.$q$, $q$Full-stack development teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["Unlimited usage","Community support","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Premium$q$, $q$$20/month per seat$q$, $q$monthly$q$, NULL, $q$["Analytics","Audit logs","Approval mode","Team collaboration features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Ultimate$q$, $q$$100/month per seat$q$, $q$monthly$q$, NULL, $q$["Everything in Premium","Priority support via Slack, Discord, or Microsoft Teams"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Stormkit Services (Enterprise)$q$, $q$Custom (reported around $500/month)$q$, $q$monthly$q$, NULL, $q$["Infrastructure setup","Service updates and monitoring","Feature development","Enterprise features","Direct Slack support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$overview$q$, $q$What Is Stormkit$q$, 2, ARRAY[$q$Stormkit is a web application deployment and hosting platform built as a self-hosted alternative to services like Vercel and Netlify. It gives development teams Git-based CI/CD, preview deployments, and production hosting while allowing the underlying infrastructure to remain under the team's own control rather than a third-party cloud.$q$, $q$The platform is designed for teams that want the developer experience of a modern hosting platform, such as automatic deployments and zero-downtime releases, without being locked into a single vendor's infrastructure or pricing model.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Stormkit automatically deploys every push to a configured branch with zero required configuration, and supports zero-downtime rolling updates so releases do not interrupt live traffic. Custom domains can be connected with automatic TLS certificate provisioning, and the platform supports a wide range of frameworks and languages including JavaScript frontends and backends, Astro, Nuxt, Next.js, Svelte, FastAPI, Go, and Rust.$q$, $q$Additional capabilities include real-time analytics and error monitoring, secure environment variable management for both client and server code, audit logs, and automated end-to-end testing on enterprise tiers. Because Stormkit is self-hostable, teams retain full data export capability and avoid platform lock-in.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Stormkit's Free plan is 0 US dollars per month with unlimited usage and community support, requiring no credit card to start. The Premium plan is 20 US dollars per month per seat and adds analytics, audit logs, approval mode, and team collaboration features. The Ultimate plan is 100 US dollars per month per seat and adds priority support through Slack, Discord, or Microsoft Teams.$q$, $q$For larger organizations, Stormkit offers a custom Stormkit Services engagement, reported around 500 US dollars per month, covering infrastructure setup, service updates, monitoring, feature development, enterprise features, and direct Slack support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Visual, in-context editor$q$, $q$Marketers can preview and edit content exactly as it will appear on the live site rather than editing in a raw form.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Component-based content model (bloks)$q$, $q$Developers build reusable content components that non-technical editors can assemble into pages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$REST and GraphQL APIs$q$, $q$Content is delivered via API to any website, app, or digital channel.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Multi-language localization$q$, $q$Manage content across multiple locales, with additional locales available on paid plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$FlowMotion workflow automation$q$, $q$Automate content approval chains and publishing workflows with configurable execution tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Enterprise governance$q$, $q$SSO, SCIM provisioning, custom roles, and workflows available on Premium and Elite plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$AI credits and tooling$q$, $q$Built-in AI credits included on every plan to support AI-assisted content workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$High availability infrastructure$q$, $q$Enterprise plans offer uptime SLAs up to 99.99 percent for mission-critical content delivery.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Visual editor bridges the usability gap common in headless CMS platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Component-based model promotes strong content reuse across channels$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Free Starter tier available for small projects$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Flexible API delivery via REST or GraphQL to any frontend$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Well-funded company with enterprise-grade governance features$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Costs scale quickly once traffic, API requests, or seats exceed the base tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Additional locales beyond the included amount cost extra on Growth plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Enterprise features like SSO and SCIM require a custom-priced Premium or Elite plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Learning the component-based (bloks) content model takes onboarding time for new teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$AI credit limits can be consumed quickly on content-heavy sites$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$What is Storyblok used for?$q$, $q$Storyblok is used as a headless CMS to manage structured content and deliver it via API to websites, mobile apps, and other digital channels, while giving marketers a visual, in-context editing experience.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Does Storyblok have a free plan?$q$, $q$Yes, the Starter plan is free and includes 1 space, 1 user seat, 100GB of traffic, and 100,000 API requests per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$How much does Storyblok cost?$q$, $q$Paid plans start at 99 US dollars per month for Growth and 349 US dollars per month for Growth Plus, with custom pricing for Enterprise-grade Premium and Elite plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Where is Storyblok headquartered?$q$, $q$Storyblok is headquartered in Linz, Austria, and was founded in 2017.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$What does headless CMS mean in Storyblok's context?$q$, $q$It means content is stored and managed independently from how it is displayed, and delivered via REST or GraphQL API to any frontend, app, or channel.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Does Storyblok support multiple languages?$q$, $q$Yes, Storyblok supports multi-locale content management, with additional locales beyond the included amount available for an extra fee on some plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Is Storyblok suitable for non-technical marketers?$q$, $q$Yes, its visual, in-context editor is designed so marketers can edit and preview content without needing a developer for routine changes.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Multi-channel content delivery$q$, $q$Enterprises use Storyblok to manage content once and deliver it consistently across websites, mobile apps, and other digital touchpoints.$q$, $q$Enterprise marketing and content teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Marketing-led website management$q$, $q$Marketing teams use the visual editor to update landing pages and campaign content without waiting on developer support.$q$, $q$Marketers and content editors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Agency and developer projects$q$, $q$Digital agencies build reusable, component-based content structures in Storyblok for multiple client websites.$q$, $q$Digital agencies and frontend developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Starter$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1 space","1 user seat","100GB traffic per month","100,000 API requests per month","2 locales","25,000 AI credits"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Growth$q$, $q$$99/month ($90.75/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["5 user seats","400GB traffic per month","1M API requests per month","2 locales included, additional at $20 each","100,000 AI credits"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Growth Plus$q$, $q$$349/month ($319.91/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["15 user seats","1TB traffic per month","4M API requests per month","10 locales included","200,000 AI credits","45-day free trial"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Premium and Elite (Enterprise)$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["GraphQL API","SSO","SCIM provisioning","Custom roles and workflows","99.9%-99.99% uptime SLA"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$overview$q$, $q$What Is Storyblok$q$, 2, ARRAY[$q$Storyblok is a headless content management system that separates content storage and delivery from the frontend presentation layer. Content is delivered through APIs to any website, mobile app, or digital channel, while a visual editor lets marketers and content teams see and edit changes in a real-time preview rather than working blind in a raw content form.$q$, $q$Founded in 2017 in Linz, Austria, Storyblok has grown into a widely adopted headless CMS, raising 47 million US dollars in funding in 2022 to expand its platform for both technical and non-technical users. The company reports its tools have been used by tens of thousands of companies across industries.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Storyblok's component-based architecture, sometimes called bloks, lets developers build reusable content blocks that marketers can then assemble into pages without needing a developer for every change. The visual editor shows a live, in-context preview of content as it will appear on the live site, bridging the usual gap between headless CMS flexibility and traditional CMS ease of use.$q$, $q$The platform supports REST and GraphQL APIs, multi-language localization, role-based access, and a workflow automation layer called FlowMotion for teams that need approval chains or content publishing automations. Enterprise plans add single sign-on, SCIM provisioning, custom roles and workflows, and high-availability uptime SLAs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Storyblok's Starter plan is free, with 1 space, 1 user seat, 100GB of monthly traffic, 100,000 API requests, 2 locales, and 25,000 AI credits. The Growth plan costs 99 US dollars per month, or about 90.75 US dollars per month billed annually, and includes 5 user seats, 400GB of traffic, 1 million API requests, and 100,000 AI credits, with additional locales available at 20 US dollars each.$q$, $q$The Growth Plus plan costs 349 US dollars per month, or about 319.91 US dollars per month billed annually, and includes 15 seats, 1TB of traffic, 4 million API requests, 10 locales, and 200,000 AI credits, plus a 45-day free trial. Premium and Elite Enterprise plans use fully custom, consumption-based pricing and add GraphQL, SSO, SCIM, custom roles and workflows, and uptime SLAs between 99.9 and 99.99 percent.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Component isolation$q$, $q$Build and preview UI components inside an isolated iframe, separate from full application logic and context.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Component Story Format$q$, $q$An open, ES6-module-based standard for describing component variations, reusable by external testing tools.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Interactive component index$q$, $q$A browsable catalog of every UI component and its documented states for team reference.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Testing integrations$q$, $q$Works with Jest, Playwright, and Cypress for interaction, accessibility, and visual testing workflows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Broad framework support$q$, $q$Supports React, Vue, Angular, Svelte, and mobile frameworks including React Native, Android, iOS, and Flutter.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Add-on ecosystem$q$, $q$Extensible via a large community add-on library for accessibility checks, design tokens, and more.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Living documentation$q$, $q$Stories double as up-to-date, interactive documentation for a design system or component library.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Open-source and free$q$, $q$Fully free to use with an active community and no licensing cost for core functionality.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Large, active community and extensive add-on ecosystem$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Broad framework support across web and mobile$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Stories double as living documentation for design systems$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Integrates cleanly with popular testing tools like Jest, Playwright, and Cypress$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Requires developer effort to write and maintain stories for every component$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Not a hosted product, so teams manage their own deployment and CI setup$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Some advanced workflows like automated visual review require a separate paid product such as Chromatic$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Initial setup and configuration can be non-trivial for complex projects$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$No official commercial support channel for the open-source core$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$What is Storybook used for?$q$, $q$Storybook is used to build, test, and document UI components in isolation from a full application, so developers can review each component's states independently.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Is Storybook free?$q$, $q$Yes, Storybook is completely free and open source with no paid tier for its core functionality.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Who maintains Storybook?$q$, $q$Storybook is maintained primarily by the team behind Chromatic, building on a project originally created by Kadira and later handed to the open-source community.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$What frameworks does Storybook support?$q$, $q$Storybook supports React, Vue, Angular, Svelte, and other web frameworks, as well as mobile frameworks including React Native, Android, iOS, and Flutter.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Is Storybook the same as Chromatic?$q$, $q$No. Storybook is a free, open-source component development tool, while Chromatic is a separate, paid visual testing and review product made by former Storybook maintainers that integrates with Storybook.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Does Storybook support testing?$q$, $q$Yes, Storybook integrates with tools like Jest, Playwright, and Cypress for interaction, accessibility, and visual testing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$When was Storybook created?$q$, $q$Storybook began as React Storybook, first released in April 2016 by the Kadira team.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Design system development$q$, $q$Design system teams use Storybook to build, document, and review reusable UI components in isolation before they ship to production apps.$q$, $q$Frontend engineers and design system teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Component-driven testing$q$, $q$Teams write interaction and accessibility tests against components in Storybook, catching regressions before integration.$q$, $q$QA and frontend engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Living UI documentation$q$, $q$Organizations use Storybook as an always-current, interactive catalog of every component and its variations for cross-team reference.$q$, $q$Product and design teams collaborating with engineering$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full component isolation and story authoring","Component Story Format","Testing integrations with Jest, Playwright, and Cypress","Broad framework support","Community add-on ecosystem"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$overview$q$, $q$What Is Storybook$q$, 2, ARRAY[$q$Storybook is an open-source development tool that lets frontend engineers build and test UI components in isolation, outside the context of a full running application. It started as React Storybook, first released in April 2016 by Kadira, a Sri Lankan startup previously known for its contributions to the Meteor ecosystem.$q$, $q$After Kadira closed at the end of 2016, Storybook development stalled until the open-source community took over maintenance in 2017. Today the project is maintained largely by the team behind Chromatic, a visual testing platform built by former Storybook maintainers, though Storybook itself remains fully open source and free.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Storybook lets developers write stories, which are declarative descriptions of a component's different states and variations, and render them inside an isolated iframe so styling and behavior can be reviewed without interference from application-level logic. Stories follow the open Component Story Format standard, making them reusable by external testing tools.$q$, $q$The tool supports interaction testing, accessibility checks, and visual testing add-ons, and maintains an interactive index of every component and its states for team reference. Framework support extends well beyond the web, covering React, Vue, Angular, and Svelte, as well as React Native, Android, iOS, and Flutter for mobile component development.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Storybook is completely free and open source, with no paid tier for the core tool itself. It is distributed on GitHub, where it has attracted more than 90,000 stars, and is used by hundreds of companies and thousands of individual developers. Optional, separately maintained products such as Chromatic offer paid visual testing and review services that integrate with Storybook, but Storybook's own component-development functionality carries no license cost.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('546237d7-afb6-42b7-8b01-ab03163155ce', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Self-hostable, open-source core$q$, $q$MIT-licensed CMS that can run on any infrastructure with no licensing fee for the Community edition.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$REST and GraphQL APIs$q$, $q$Content is exposed automatically through both REST and GraphQL endpoints.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Customizable content types$q$, $q$Developers define content structures and relationships specific to their application.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Role-based access control$q$, $q$Granular permissions for admin users and API consumers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Strapi AI content assistance$q$, $q$AI-assisted content creation available on paid Growth and Enterprise plans, billed by credits.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Strapi Cloud managed hosting$q$, $q$Fully managed deployment option with global CDN, automated backups, and custom domains.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Plugin and extension system$q$, $q$Extend the admin panel and API behavior with custom or community-built plugins.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Enterprise governance$q$, $q$Review workflows, audit logs, and SOC 2 reporting available on Enterprise plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Free, open-source Community edition with unlimited entries and API calls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Full self-hosting control avoids vendor lock-in on core content infrastructure$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Both REST and GraphQL APIs supported natively$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Strong enterprise adoption with 450-plus enterprise customers and significant funding$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Optional Strapi Cloud removes the need to manage infrastructure directly$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Self-hosting requires ongoing server management, security patching, and scaling effort$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Strapi AI credits are limited on paid plans, with overage charged per additional credit$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$SSO is an additional paid add-on rather than included in the Growth plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Strapi Cloud project-based pricing can add up for organizations running many separate projects$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Advanced compliance features like SOC 2 reporting require the custom Enterprise tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Is Strapi free to use?$q$, $q$Yes, Strapi's self-hosted Community edition is free forever under the MIT license, with unlimited entries, API calls, content types, and locales.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$What is the difference between self-hosted Strapi and Strapi Cloud?$q$, $q$Self-hosted Strapi runs on infrastructure you manage yourself, while Strapi Cloud is a fully managed hosting service with project-based pricing that handles infrastructure, backups, and scaling for you.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$How much does Strapi Cloud cost?$q$, $q$Strapi Cloud starts at 35 US dollars per month per project for the Starter plan, with Pro at 90 US dollars per month and Business at 450 US dollars per month, plus a custom Business+ tier.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Does Strapi support GraphQL?$q$, $q$Yes, Strapi automatically exposes content through both REST and GraphQL APIs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Who founded Strapi and where is it based?$q$, $q$Strapi was founded in 2016 and is headquartered in Paris, France, with a remote-first team spread across more than 10 countries.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Does Strapi include AI features?$q$, $q$Yes, Strapi AI content assistance is available on the paid Growth and Enterprise self-hosted plans, billed through monthly credit allowances.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Is Strapi suitable for enterprise use?$q$, $q$Yes, Strapi reports more than 450 enterprise customers and offers an Enterprise tier with review workflows, audit logs, and SOC 2 compliance reporting.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Self-hosted content backend$q$, $q$Development teams deploy Strapi on their own infrastructure to power websites and apps with full data ownership.$q$, $q$Backend and full-stack development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Omnichannel content delivery$q$, $q$Organizations use Strapi's REST and GraphQL APIs to deliver the same content to web, mobile, and IoT applications.$q$, $q$Enterprises with multiple digital products$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Managed CMS via Strapi Cloud$q$, $q$Teams that want Strapi's flexibility without managing servers use Strapi Cloud for hosting, backups, and scaling.$q$, $q$Startups and lean engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Community (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["MIT open-source license","Role-based access control","REST and GraphQL APIs","Unlimited entries and API calls","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Growth (Self-Hosted)$q$, $q$$45/month (3 seats)$q$, $q$monthly$q$, NULL, $q$["Additional seats at $15/month each","Strapi AI (1,000 credits per month)","Live preview","Releases","30-day content history","Basic support"]$q$::jsonb, 1);
