INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Strapi Cloud Pro$q$, $q$$90/month per project$q$, $q$monthly or annual$q$, NULL, $q$["1M API requests","250GB storage and bandwidth","Multi-environment","Weekly and manual backups","CRON jobs"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Strapi Cloud Business$q$, $q$$450/month per project$q$, $q$monthly or annual$q$, NULL, $q$["10M API requests","1,000GB storage and bandwidth","Daily backups","99.9% uptime SLA","1 extra environment"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$overview$q$, $q$What Is Strapi$q$, 2, ARRAY[$q$Strapi is an open-source headless content management system built with JavaScript and Node.js, designed to give developers full control over content modeling, APIs, and hosting. Unlike fully managed SaaS CMS platforms, Strapi's core is self-hostable and released under the MIT license, so teams can run it on their own infrastructure at no licensing cost.$q$, $q$Founded in 2016 and headquartered in Paris, France, Strapi has grown into one of the most widely adopted open-source CMS projects, backed by tens of millions of dollars in venture funding and used by more than 450 enterprise customers alongside a large open-source community.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Strapi provides customizable content types, role-based access control, and both REST and GraphQL APIs out of the box, with unlimited content entries, API calls, locales, and components across all plans, including the free Community tier. A plugin system lets developers extend the admin panel and API behavior for custom workflows.$q$, $q$Paid self-hosted plans add Strapi AI content assistance, live preview of content changes, scheduled releases, and extended content history, while Enterprise tiers add review workflows, audit logs, and SOC 2 compliance reporting. For teams that prefer not to manage infrastructure, Strapi Cloud offers fully managed hosting with built-in email, a global CDN, custom domains, and automated backups.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Strapi's self-hosted Community plan is free forever under the MIT license, with unlimited entries, API calls, content types, locales, and components. The self-hosted Growth plan costs 45 US dollars per month and includes 3 seats, with additional seats at 15 US dollars per month each, adding Strapi AI credits, live preview, scheduled releases, and 30 days of content history. Self-hosted Enterprise pricing is custom and adds review workflows, audit logs, 365 days of content history, and SOC 2 reporting.$q$, $q$For managed hosting, Strapi Cloud's Starter plan is 35 US dollars per month per project with 100,000 API requests and 50GB of storage and bandwidth. The Pro plan is 90 US dollars per month per project with 1 million API requests and 250GB of storage and bandwidth. The Business plan is 450 US dollars per month per project with 10 million API requests, 1,000GB of storage and bandwidth, and a 99.9 percent uptime SLA, with a custom Business+ tier above that. Annual billing on Strapi Cloud saves up to 17 percent.$q$]::text[], 2);
