INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$What is Streak used for?$q$, $q$Streak is used as a CRM inside Gmail, letting sales, recruiting, support, and other teams track pipelines, contacts, and deals without leaving their inbox.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$Is Streak free?$q$, $q$Yes, Streak offers a free plan with 500 contacts and 50 mail merge emails per day, along with email tracking and snippets.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$How much does Streak cost?$q$, $q$Paid plans range from 15 US dollars per user per month for Solo to 129 US dollars per user per month for Enterprise, with a roughly 20 percent discount for annual billing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$Who founded Streak?$q$, $q$Streak was founded in 2011 by Aleem Mawani and Omar Ismail, and went through Y Combinator's Summer 2011 batch.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$Does Streak work outside of Gmail?$q$, $q$Streak is built specifically as a Gmail extension and CRM layer, so it is designed to work inside the Gmail interface rather than as a standalone application.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$Does Streak support mail merge?$q$, $q$Yes, mail merge is available on all plans, with daily sending limits that increase from the Free plan through Enterprise.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$Where is Streak based?$q$, $q$Streak is headquartered in San Francisco, California, United States.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$Sales pipeline management$q$, $q$Sales teams track deals through customizable pipeline stages directly inside Gmail, without adopting a separate CRM tool.$q$, $q$Sales teams and account executives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$Recruiting and candidate tracking$q$, $q$Recruiters use Streak's pipeline views to track candidates through interview stages using their existing email workflow.$q$, $q$Recruiters and talent teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$Customer support and deal flow tracking$q$, $q$Support and business development teams use shared pipelines to manage tickets or investment deal flow collaboratively.$q$, $q$Support teams and venture or business development teams$q$, 2);
