INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$Enterprise$q$, $q$$129/user/month$q$, $q$monthly or annual$q$, NULL, $q$["Custom roles","Data validation","Dedicated support","500 AI credits per user per month","Minimum 10 users"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$overview$q$, $q$What Is Streak$q$, 2, ARRAY[$q$Streak is a CRM that lives entirely inside Gmail rather than as a separate application. It was founded in 2011 by Aleem Mawani, a former Google product manager, and Omar Ismail, and went through Y Combinator's Summer 2011 accelerator batch before graduating in early 2012.$q$, $q$The company is headquartered in San Francisco, California, and built Streak to solve its own founders' sales workflow needs before realizing teams across recruiting, support, deal flow, and project management wanted the same inbox-native approach to tracking relationships and pipelines.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Streak adds pipeline views directly into the Gmail interface, letting teams track deals, candidates, support tickets, or any other process as it moves through customizable stages without leaving their inbox. Shared pipelines give teammates visibility into the same data, while email tracking shows when recipients open messages.$q$, $q$The platform includes mail merge for sending personalized bulk emails, reusable email snippets, and a thread splitter for managing multiple conversations in one thread. Higher-tier plans add advanced reporting, third-party integrations and automations, custom roles, data validation rules, and AI credits for AI-assisted workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ec5fff7f-2e72-4779-b7d5-769d8491fa4f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Streak's Free plan includes 500 contacts and 50 mail merge emails per day, along with core features like email tracking, snippets, and thread splitting. The Solo plan is 15 US dollars per user per month and raises limits to 5,000 contacts and 800 mail merge emails per day, aimed at individual users.$q$, $q$The Pro plan is 49 US dollars per user per month and includes unlimited contacts, shared pipelines, and 20 AI credits per user per month. The Pro+ plan is 69 US dollars per user per month, adding advanced reports, integrations, automations, and 150 AI credits per user per month, with a 14-day free trial. The Enterprise plan is 129 US dollars per user per month, requires at least 10 users, and adds custom roles, data validation, and dedicated support including a direct line to Streak's CEO. Annual billing offers roughly a 20 percent discount versus monthly billing across paid tiers.$q$]::text[], 2);
