-- в”Ђв”Ђ Stoat в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Stoat (formerly Revolt) is a free, open-source chat and community platform built as a privacy-first alternative to Discord, Slack, and Telegram.$q$, short_description),
  pricing_model = COALESCE($q$free/open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Stoat: Free Open-Source Discord Alternative$q$, seo_title),
  seo_meta_description = COALESCE($q$Stoat is a free, open-source chat and community platform built as a privacy-first alternative to Discord. See features, pricing, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Stoat is a free, open-source instant messaging and community platform originally launched as Revolt on January 27, 2021, and rebranded to Stoat in October 2025 after a trademark dispute over the Revolt name. It is developed by Revolt Platforms Ltd, a company registered in London, United Kingdom. Stoat positions itself as a privacy-first alternative to Discord, Slack, and Telegram, offering servers, channels, text chat, voice chat, file sharing, and markdown support, with a Rust-based backend and a codebase released under the GNU Affero General Public License v3. There is no paid subscription tier for the core product: Stoat is entirely free to use, funded by user donations, and can be self-hosted by anyone who wants full control over their own infrastructure. The platform grew from an early Hacker News launch to over 100,000 registered users by mid-2023 and surged past 500,000 accounts in October 2024 after Discord faced regional restrictions in Turkey and Russia, with another growth wave in early 2026 following Discord age-verification changes. Clients are available for Windows, macOS, Linux, Android, and the web, with iOS in development. Stoat is best suited for privacy-conscious communities, open-source enthusiasts, and gaming or hobbyist groups seeking a Discord alternative without corporate data collection.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4ec9cb7b-3758-48d4-b21c-ca4d6d43754e';

