-- в”Ђв”Ђ Stonly в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Stonly is an interactive guide and self-serve customer support platform that helps companies build step-by-step decision trees, walkthroughs, and AI-assisted help content.$q$, short_description),
  pricing_model = COALESCE($q$freemium/subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Levallois-Perret, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Stonly Pricing and Features: Interactive Guide Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Stonly builds interactive guides and AI-assisted self-service support. Compare Stonly pricing plans, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Stonly is a customer support and product adoption platform, founded in 2018 and headquartered in Levallois-Perret, France, near Paris, with roughly 51-200 employees. It lets support, product, and success teams build interactive guides, decision trees, walkthroughs, and knowledge base content that can be embedded on websites, in-app, or inside help desk tools like Zendesk, Freshdesk, and Front. Stonly also offers AI-driven automations that route customers to the right guide or answer without needing a live agent, positioning it as a self-service deflection tool that reduces support ticket volume. Pricing starts with a free Basic tier that includes 400 monthly guide views, 5 published guides, and 1 team member. Paid tiers include Starter, priced around 99 to 124 US dollars per month depending on billing cycle, which unlocks up to 30 guides, a custom knowledge base, analytics, and help desk integrations, and Business, priced around 199 to 249 US dollars per month, which adds unlimited guides, multiple knowledge bases, multilingual support, and SEO optimization. An Enterprise tier offers custom integrations, single sign-on, and dedicated support at custom pricing. Stonly is best suited for SaaS companies and e-commerce brands that want to reduce support ticket volume through guided self-service.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '28d621bc-8148-478e-91f4-93954281f173';

