-- в”Ђв”Ђ Stoplight в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Stoplight is an API design, documentation, and mocking platform that helps teams build APIs using a design-first workflow, now operating as part of SmartBear.$q$, short_description),
  pricing_model = COALESCE($q$freemium/subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Austin, Texas, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Stoplight: API Design and Documentation Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Stoplight helps teams design, document, and mock APIs with a design-first workflow. See Stoplight pricing, features, and how it fits into SmartBear.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Stoplight is an API design, documentation, and mock-server platform founded in 2015 by Marc MacLeod in Austin, Texas. It promotes a design-first approach to building APIs, allowing teams to visually design OpenAPI specifications, generate interactive documentation, create reusable style guides and components, and spin up mock servers before writing backend code. Before being acquired, Stoplight raised roughly 21.9 to 26 million US dollars in funding, including an 11 million dollar Series B led by Next Coast Ventures in 2021. In August 2023, SmartBear announced an agreement to acquire Stoplight to broaden its API development and documentation portfolio, and Stoplight's governance, mocking, and visual editing capabilities have since been integrated into SmartBear's broader API platform. Stoplight offers a free plan for a single user and project, with paid plans historically including Basic at roughly 44 to 56 US dollars per month for 3 users, Startup at roughly 113 to 147 US dollars per month for 8 users, and Pro Team at roughly 362 to 453 US dollars per month for 15 users, plus a custom Enterprise tier. Notable customers have included Calendly, Schneider Electric, Fiserv, and PagerDuty. Stoplight is best suited for API platform teams, developer experience teams, and organizations standardizing API governance across many services.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '28f84c5e-8df6-4846-8228-5943ba6223e8';

