-- в”Ђв”Ђ Stormkit в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Stormkit is a self-hosted deployment and hosting platform for web applications, positioned as an alternative to Vercel and Netlify with full infrastructure control.$q$, short_description),
  pricing_model = COALESCE($q$freemium/subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Stormkit: Self-Hosted Vercel and Netlify Alternative$q$, seo_title),
  seo_meta_description = COALESCE($q$Stormkit is a self-hosted web app deployment platform. Compare Stormkit pricing, features, and how it works as a Vercel and Netlify alternative.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Stormkit is a deployment and hosting platform for modern web applications that positions itself as a self-hosted alternative to Vercel and Netlify. It supports Git-based deployments from GitHub, GitLab, and Bitbucket, with automatic builds triggered on every push, zero-downtime rolling deployments, custom domains with automatic TLS certificate provisioning, and support for frameworks and languages including Node.js, Astro, Nuxt, Next.js, Svelte, FastAPI, Go, and Rust. Because it can be self-hosted on a team's own infrastructure, Stormkit is aimed at engineering teams that want CI/CD and preview deployments without vendor lock-in or the recurring costs of fully managed platforms, with the company claiming up to 47 percent lower infrastructure costs versus comparable managed hosting. The platform reports serving over 600 million requests with 99.9 percent uptime over a 365-day period. Pricing includes a free plan with unlimited usage and community support, a Premium plan at 20 US dollars per month per seat adding analytics, audit logs, approval mode, and team features, and an Ultimate plan at 100 US dollars per month per seat adding priority support through Slack, Discord, or Teams. An Enterprise offering called Stormkit Services provides custom infrastructure setup, monitoring, and dedicated support. Specific founding year, headquarters, and employee count are not publicly confirmed.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a';

