-- в”Ђв”Ђ Storyblok в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Storyblok is a headless content management system with a visual editor that lets marketers and developers manage structured content across any frontend or channel.$q$, short_description),
  pricing_model = COALESCE($q$freemium/subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Linz, Austria$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Storyblok: Headless CMS with Visual Editor Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Storyblok is a headless CMS with a visual editor for marketers and developers. Compare Storyblok pricing plans, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Storyblok is a headless content management system founded in 2017 and headquartered in Linz, Austria, with several hundred employees spread across multiple continents. It combines an API-first, component-based content architecture with a visual editor that lets non-technical marketers preview and edit content in context, while developers build and reuse structured content components across websites, apps, and other channels. Storyblok raised 47 million US dollars in a 2022 funding round aimed at growing its headless CMS for non-technical users, and by that time its tools were used by roughly 74,000 companies. Pricing starts with a free Starter plan for 1 space and 1 user seat with 100GB of monthly traffic and 100,000 API requests. The Growth plan is 99 US dollars per month, or roughly 90.75 US dollars per month billed annually, and includes 5 user seats, 400GB of traffic, and 1 million API requests. The Growth Plus plan is 349 US dollars per month, or roughly 319.91 US dollars per month annually, and includes 15 seats, 1TB of traffic, and 4 million API requests, plus a 45-day free trial. Enterprise-grade Premium and Elite plans offer custom pricing with GraphQL, SSO, SCIM, custom roles and workflows, and uptime SLAs up to 99.99 percent. Storyblok is best suited for marketing teams, agencies, and enterprises that need a flexible, component-driven CMS across multiple digital channels.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6e2b87a4-c5be-4f23-acc9-dd611b9c5856';

