  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Strapi: Open-Source Headless CMS Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Strapi is an open-source, self-hostable headless CMS with REST and GraphQL APIs. Compare Strapi pricing, Strapi Cloud plans, and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Strapi is an open-source, JavaScript-based headless content management system founded in 2016 and headquartered in Paris, France, with a remote-first team of roughly 51 to 200 employees across more than 10 countries. It gives developers a self-hostable, MIT-licensed CMS with REST and GraphQL APIs, customizable content types, and role-based access control, making it a common choice for teams that want full ownership of their content infrastructure rather than a fully managed SaaS CMS. Strapi has raised roughly 45 to 49 million US dollars in funding, including a 31 million dollar Series B round led by CRV in 2022, and reports more than 450 enterprise customers. Strapi's self-hosted Community plan is free forever under an MIT license with unlimited entries and API calls. The paid, self-hosted Growth plan is 45 US dollars per month for 3 seats, with additional seats at 15 US dollars per month each, adding Strapi AI credits, live preview, and content history. Enterprise self-hosted pricing is custom and adds review workflows, audit logs, and SOC 2 reporting. Strapi also offers a managed Strapi Cloud service with Starter at 35 US dollars per month per project, Pro at 90 US dollars per month per project, and Business at 450 US dollars per month per project, plus a custom Business+ tier.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9eb13448-c65d-4848-a1d8-3d2a010b723d';

