-- в”Ђв”Ђ Streak в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Streak is a CRM that runs entirely inside Gmail, letting sales, support, and other teams manage pipelines and contacts without leaving their inbox.$q$, short_description),
  pricing_model = COALESCE($q$freemium/subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Streak: CRM for Gmail Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Streak is a CRM built inside Gmail for sales and support teams. Compare Streak pricing plans, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Streak is a customer relationship management tool built directly inside Gmail, founded in 2011 by former Google product manager Aleem Mawani and co-founder Omar Ismail. The company went through Y Combinator's Summer 2011 batch and is headquartered in San Francisco, California, with a small team of roughly 11 to 50 employees. Rather than requiring users to switch to a separate CRM application, Streak overlays pipeline management, shared team visibility, mail merge, email tracking, and automation directly onto the Gmail interface, making it popular with sales, recruiting, support, and deal-flow teams that live in their inbox. Streak offers a free plan with 500 contacts and 50 mail merge emails per day. The Solo plan is 15 US dollars per user per month with 5,000 contacts and 800 mail merge emails per day. The Pro plan is 49 US dollars per user per month and includes unlimited contacts, shared pipelines, and 20 AI credits per user per month. The Pro+ plan is 69 US dollars per user per month and adds advanced reports, integrations, automations, and 150 AI credits per user per month. The Enterprise plan is 129 US dollars per user per month, requires a minimum of 10 users, and adds custom roles, data validation, and dedicated support. Annual billing offers a 20 percent discount across paid plans.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ec5fff7f-2e72-4779-b7d5-769d8491fa4f';

